mapper.select:
SELECT * FROM ( SELECT 'quick_record' AS source, record_no AS record_no, type AS direction, amount, IFNULL(category, '其他') AS category, IFNULL(related_name, '') AS related_name, IFNULL(payment_method, '') AS payment_method, IFNULL(remark, '') AS remark, create_time FROM fin_record WHERE deleted = 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}
AND type = 'income'
AND type = 'expense'
UNION ALL
SELECT 'member_recharge' AS source, CONCAT('MR', id) AS record_no, 'income' AS direction, amount, '会员充值' AS category, IFNULL((SELECT member_name FROM mem_member WHERE id = mem_member_transaction.member_id), '未知会员') AS related_name, '' AS payment_method, IFNULL(remark, '') AS remark, create_time FROM mem_member_transaction WHERE deleted = 0 AND type = 'recharge'
AND create_time >= #{startDate}
AND create_time <= #{endDate}
UNION ALL
SELECT 'member_consume' AS source, CONCAT('MC', id) AS record_no, 'expense' AS direction, amount, '会员消费' AS category, IFNULL((SELECT member_name FROM mem_member WHERE id = mem_member_transaction.member_id), '未知会员') AS related_name, '' AS payment_method, IFNULL(remark, '') AS remark, create_time FROM mem_member_transaction WHERE deleted = 0 AND type = 'consume'
AND create_time >= #{startDate}
AND create_time <= #{endDate}
UNION ALL
SELECT 'factory_bill' AS source, bill_no AS record_no, 'expense' AS direction, IFNULL(paid_amount, 0) AS amount, '工厂账单' AS category, IFNULL(factory_name, '') AS related_name, '' AS payment_method, CONCAT('月份: ', month) AS remark, create_time FROM fac_factory_bill WHERE deleted = 0 AND IFNULL(paid_amount, 0) > 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}
UNION ALL
SELECT 'square_income' AS source, CONCAT('SQ', id) AS record_no, 'income' AS direction, IFNULL(quoted_price, 0) - IFNULL(actual_income, 0) AS amount, '设计广场收入' AS category, IFNULL(designer_name, '') AS related_name, '' AS payment_method, CONCAT('需求: ', IFNULL(title, '')) AS remark, create_time FROM sq_income WHERE deleted = 0 AND status = 2 AND IFNULL(quoted_price, 0) - IFNULL(actual_income, 0) > 0
AND create_time >= #{startDate}
AND create_time <= #{endDate}
) AS all_flow ORDER BY create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM (
    SELECT id FROM fin_record WHERE deleted = 0

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


        AND type = 'income'


        AND type = 'expense'


    UNION ALL

    SELECT id FROM mem_member_transaction WHERE deleted = 0 AND type = 'recharge'

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


    UNION ALL

    SELECT id FROM mem_member_transaction WHERE deleted = 0 AND type = 'consume'

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


    UNION ALL

    SELECT id FROM fac_factory_bill WHERE deleted = 0 AND IFNULL(paid_amount, 0) > 0

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


    UNION ALL

    SELECT id FROM sq_income WHERE deleted = 0 AND status = 2 AND IFNULL(quoted_price, 0) - IFNULL(actual_income, 0) > 0

        AND create_time >= #{startDate}


        AND create_time <= #{endDate}

) AS all_count
